# orchestrator.py
from typing import TypedDict


class AgentState(TypedDict):
    step: int
    tool_name: str | None
    tool_result: object | None
    finished: bool


def initial_state() -> AgentState:
    return {"step": 0, "tool_name": None, "tool_result": None, "finished": False}


def advance(state: AgentState, tool_name: str, result: object) -> AgentState:
    return {
        "step": state["step"] + 1,
        "tool_name": tool_name,
        "tool_result": result,
        "finished": False,
    }


