from __future__ import annotations
from typing import Literal, Union
from pydantic import BaseModel, Field


class SearchToolArgs(BaseModel):
    query: str = Field(description="""The search query string.""")
    limit: int = Field(default=5, ge=1, le=20, description="""Max results to return.""")


class DeleteFileArgs(BaseModel):
    path: str = Field(description="""Relative path under workspace root.""")
    confirm: bool = Field(default=False, description="""Set true to confirm destructive action.""")


ToolArgs = Union[SearchToolArgs, DeleteFileArgs]


class ToolCall(BaseModel):
    tool: Literal["search", "delete_file"]
    args: dict[str, object]  # raw from LLM; parsed per-tool below

    def parse_args(self) -> ToolArgs:
        if self.tool == "search":
            return SearchToolArgs.model_validate(self.args)
        elif self.tool == "delete_file":
            return DeleteFileArgs.model_validate(self.args)
        raise ValueError(f"Unknown tool: {self.tool}")


