import json
from pydantic import ValidationError
from models import ToolCall


def handle_llm_response(raw_response: str) -> ToolCall | None:
    """Parse LLM JSON into a typed ToolCall; return None and log on failure."""
    try:
        data = json.loads(raw_response)
        return ToolCall.model_validate(data)
    except (json.JSONDecodeError, ValidationError) as exc:
        print(f"[WARN] LLM output invalid: {exc}")
        return None


