from typing import TypedDict

class Step(TypedDict):
    name: str
    result: object | None
    retries: int

def build_step(name: str) -> Step:
    return {"name": name, "result": None, "retries": 0}

from typing import Literal, assert_never

ToolName = Literal["search", "delete_file", "send_email"]

def dispatch(name: ToolName, args: object) -> str:
    if name == "search":
        return run_search(args)
    elif name == "delete_file":
        return run_delete(args)
    elif name == "send_email":
        return run_email(args)
    else:
        # mypy/pyright report an error here if a new ToolName value is
        # added to the Literal above without adding a branch below.
        assert_never(name)
